    else:
        searcher = GitHubSearcher(
            token=args.token, 
            cache_dir=Path(args.cache_dir) or DEFAULT_CACHE_DIR,
            veto_file=Path("veto_terms.txt") if args.veto else None
        )

    # Execute searches
    if args.dry_run:
        # Simulate results for testing
        results = simulate_search(patterns=args.pattern, extra=extra_filters)
    else:
        results = aggregate_results(searcher, patterns=args.pattern, extra=extra_filters)

