    if out_path:
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(json.dumps(results, indent=2))
        log.info("Results written to %s (%d entries)", out_path, len(results))
    else:
        print(json.dumps(results, indent=2))

def aggregate_results(searcher: Optional[GitHubSearcher], patterns: List[str], extra: Dict[str, str]) -> List[Dict[str, Any]]:
    """
    Run each pattern through the searcher (or simulate in dry-run mode), collect flat results,
    and filter out any hits matching veto patterns.
    """
    all_results = []
    for pat in patterns:
        # Validate pattern before execution
        issues = validate_pattern(pat)
        if issues:
            log.warning("Pattern validation issues for '%s': %s", pat, ", ".join(issues))
        log.info("Searching pattern: %s", pat)
        if searcher:
            payload = searcher.search(pat, extra)
        else:
            # Dry-run simulation
            payload = {"query": pat, "total_count": 0, "items": []}
        # Pass the original query for downstream reference
        payload["query"] = pat
        for hit in flatten_hits(payload, searcher or GitHubSearcher(), pat):
            # Veto check on the matching text
            if searcher and searcher._should_veto(hit.get("matching_text", "")):
                log.debug("Vetoed hit in %s:%s", hit.get("repository", {}).get("name"), hit.get("file_path"))
                continue
            all_results.append(hit)
    return all_results

